# Utility module providing math and string helper functions

class MathHelper:
    multiplier: int

    def __init__(self, mult: int):
        self.multiplier = mult

    def apply(self, value: int) -> int:
        return value * self.multiplier

    def power(self, base: int, exponent: int) -> int:
        result: int = 1
        i: int = 0
        while i < exponent:
            result *= base
            i += 1
        return result


class StringHelper:
    prefix: str

    def __init__(self, p: str):
        self.prefix = p

    def format_message(self, content: str) -> str:
        return f"{self.prefix}: {content}"

    def repeat(self, text: str, count: int) -> str:
        result: str = ""
        i: int = 0
        while i < count:
            result += text
            i += 1
        return result


def calculate_sum(numbers: list[int]) -> int:
    total: int = 0
    for num in numbers:
        total += num
    return total


def find_max(a: int, b: int, c: int) -> int:
    max_val: int = a
    if b > max_val:
        max_val = b
    if c > max_val:
        max_val = c
    return max_val
